using System;
using System.Linq;
using Microsoft.EntityFrameworkCore;

public class EventContext : DbContext
{
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer("YourConnectionStringHere");
    }
}

public class Ticket
{
    public int Id { get; set; }
    public string EventName { get; set; }
    public int TotalSeats { get; set; }
    public int SoldSeats { get; set; }
}

public class TicketService
{
    private readonly EventContext _context;

    public TicketService(EventContext context)
    {
        _context = context;
    }

    public bool PurchaseTickets(string eventName, int quantity)
    {
        var ticket = _context.Tickets.FirstOrDefault(t => t.EventName == eventName);
        if (ticket == null)
            return false;

        lock (ticket)
        {
            var availableSeats = ticket.TotalSeats - ticket.SoldSeats;
            if (availableSeats < quantity)
                return false;

            ticket.SoldSeats += quantity;
            _context.SaveChanges();
            return true;
        }
    }
}